// inferred-not-tested。默认导出 ParCoords 工厂;需外链 parcoords.css,容器要 class="parcoords" + 显式尺寸。d3 经嵌套 +esm 自解析。最小链来自 demo/basic.html。
import ParCoords from 'https://cdn.jsdelivr.net/npm/parcoord-es@2.2.10/+esm';
const css = document.createElement('link'); css.rel = 'stylesheet'; css.href = 'https://cdn.jsdelivr.net/npm/parcoord-es@2.2.10/dist/parcoords.css'; document.head.appendChild(css);
const el = document.getElementById('parcoords'); el.className = 'parcoords'; el.style.width = '700px'; el.style.height = '400px';
const pc = ParCoords()(el).data(data.rows).render().createAxes().reorderable().brushMode('1D-axes');

