// CSS 落 shadow;bind 走 d3 select(node),直传 shadow 内元素即可(已验证接受 DOM 节点)。
import ParCoords from 'https://cdn.jsdelivr.net/npm/parcoord-es@2.2.10/+esm';
const css = document.createElement('link'); css.rel = 'stylesheet'; css.href = 'https://cdn.jsdelivr.net/npm/parcoord-es@2.2.10/dist/parcoords.css'; shadowRoot.appendChild(css);
const el = document.createElement('div'); el.className = 'parcoords'; el.style.width = '700px'; el.style.height = '400px'; shadowRoot.appendChild(el);
const pc = ParCoords()(el).data(data.rows).render().createAxes().reorderable().brushMode('1D-axes');

